  background: color-mix(in oklab, var(--panel) 74%, transparent);
  white-space: nowrap;
}

.plant-info-item {
  display: inline-flex;
  align-items: baseline;
  gap: 5px;
}

.plant-info-key {
  font: 700 10px "Inter", sans-serif;
  letter-spacing: 0.12em;
  color: var(--text-2);
}

.plant-info-value {
  font: 700 13px "JetBrains Mono", monospace;
  letter-spacing: 0;
  color: var(--text);
}

.plant-info.warning {
  border-color: color-mix(in oklab, oklch(72% 0.15 75) 45%, var(--line-soft));
}

@keyframes ws-pulse {
  0%, 100% {
    box-shadow: 0 0 0 0 color-mix(in oklab, var(--run) 55%, transparent);
  }
  50% {
    box-shadow: 0 0 0 6px color-mix(in oklab, var(--run) 0%, transparent);
  }
}

@keyframes ws-blink {
  0%, 50% { opacity: 1; }
  51%, 100% { opacity: 0.3; }
}

.legend {
  position: absolute;
  right: 22px;
  bottom: 35px;
  display: grid;
  grid-template-columns: 1fr;
  width: 230px;
  border: 1px solid #2b3138;
  border-radius: 0;
  background: #151a20;
  box-shadow: 0 10px 26px rgba(0, 0, 0, 0.28);
  font: 500 12px "Inter", sans-serif;
  color: #e8edf2;
  letter-spacing: 0;
  z-index: 5;
  overflow: hidden;
}

.legend::before {
  content: "Name";
  padding: 8px 12px 7px 34px;
  border-bottom: 1px solid #2b3138;
  color: #5794f2;
  font: 600 12px "Inter", sans-serif;
}

.legend-item {
  display: grid;
  grid-template-columns: 14px 1fr;
  align-items: center;
  gap: 8px;
  min-height: 24px;
  padding: 4px 10px 4px 12px;
  border-bottom: 1px solid #2b3138;
  white-space: nowrap;
  background: #151a20;
}

.legend-item:last-child {
  border-bottom: 0;
}

.legend-swatch {
  width: 14px;
  height: 3px;
  border-radius: 2px;
}

.legend-swatch.cwr {
  background: var(--cwr);
}

.legend-swatch.cws {
  background: var(--cws);
}

.legend-swatch.chws {
  background: var(--chws);
}

.legend-swatch.chwr {
  background: var(--chwr);
}

.legend-swatch.bypass {
  background: var(--bypass);
}

.canvas.theme-light .legend {
  border-color: #d1d9e6;
  background: #ffffff;
  box-shadow: 0 10px 26px rgba(15, 23, 42, 0.12);
  color: #1f2937;
}

.canvas.theme-light .legend::before {
  border-bottom-color: #d1d9e6;
  color: #2563eb;
}

.canvas.theme-light .legend-item {
  border-bottom-color: #d1d9e6;
  background: #ffffff;
}

.canvas.theme-dark .legend {
  border-color: #2b3138;
  background: #151a20;
  box-shadow: 0 10px 26px rgba(0, 0, 0, 0.28);
  color: #e8edf2;
}

.canvas.theme-dark .legend::before {
  border-bottom-color: #2b3138;
  color: #5794f2;
}

.canvas.theme-dark .legend-item {
  border-bottom-color: #2b3138;
  background: #151a20;
}

.building-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.building-title {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.building-icon {
  width: 36px;
  height: 36px;
  border: 1.5px solid var(--line);
  border-radius: 4px;
  background: var(--panel);
  position: relative;
}

.building-icon::before {
  content: "";
  position: absolute;
  left: 8px;
  top: 8px;
  right: 8px;
  height: 1.5px;
}

.building-load-rt {
  font: 600 52px "JetBrains Mono", monospace;
  letter-spacing: -0.04em;
  margin-top: 16px;
}

.building-load-rt .unit {
  font-size: 22px;
  margin-left: 8px;
  font-weight: 500;
  letter-spacing: 0;
}

.building-temps {
  margin-top: auto;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.building-temp {
  background: var(--panel);
  border: 1px solid color-mix(in oklab, var(--line) 30%, transparent);
  padding: 8px 12px 8px 16px;
  border-radius: 6px;
  position: relative;
  overflow: hidden;
}

.building-temp::before {
  content: "";
  position: absolute;
  left: 0;
  top: 8px;
  bottom: 8px;
  width: 4px;
}

.building-temp.chws::before {
  background: var(--chws);
}

.building-temp.chwr::before {
  background: var(--chwr);
}

.building-temp .k {
  font: 500 10px "Inter", sans-serif;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-2);
}

.building-temp .v {
  font: 600 22px "JetBrains Mono", monospace;
  color: var(--text);
  margin-top: 2px;
}

.building-temp .v .unit {
  font-size: 11px;
  color: var(--text-2);
  margin-left: 2px;
}

.building {
  position: absolute;
  left: 1427px;
  top: 338px;
  width: 320px;
  height: 250px;
  padding: 18px 20px;
  display: flex;
  flex-direction: column;
}

// @keyframes blinker {
//   50% {
//     opacity: 0;
//   }
// }

@keyframes blinker {
  0%, 100% {
    background-color: color-mix(in oklab, oklch(64% 0.2 25) 16%, var(--panel));
  }
  50% {
    background-color: transparent;
  }
}

.availability-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  margin-left: 6px;
  border-radius: 50%;
  font-size: 10px;
  vertical-align: middle;
}

.availability-icon:empty {
  display: none;
}

.availability-icon.maintenance {
  color: oklch(72% 0.15 75);
  background: color-mix(in oklab, oklch(72% 0.15 75) 16%, transparent);
  border: 1px solid color-mix(in oklab, oklch(72% 0.15 75) 55%, var(--line-soft));
}

.availability-icon.disabled {
  color: var(--muted);
  background: color-mix(in oklab, var(--muted) 14%, transparent);
  border: 1px solid color-mix(in oklab, var(--muted) 45%, var(--line-soft));
}

.availability-icon.unavailable {
  color: oklch(64% 0.2 25);
  background: color-mix(in oklab, oklch(64% 0.2 25) 14%, transparent);
  border: 1px solid color-mix(in oklab, oklch(64% 0.2 25) 45%, var(--line-soft));
}

.chiller.maintenance,
.ct-row.maintenance {
  border-color: color-mix(in oklab, oklch(72% 0.15 75) 45%, var(--line));
}

.chiller.disabled,
.ct-row.disabled {
  border-color: color-mix(in oklab, var(--muted) 45%, var(--line));
  opacity: 0.76;
}

.chiller.unavailable,
.ct-row.unavailable {
  border-color: color-mix(in oklab, oklch(64% 0.2 25) 40%, var(--line));
}
